import { useState, useCallback } from 'react';
import { GoogleGenAI, Type } from "@google/genai";
import { FileModel, Transaction } from '../types';

interface UseAIPatternTeacherProps {
    gridData: string[][];
    setGridData: (data: string[][]) => void;
    setActiveMapping: (mapping: any) => void;
    showToast: (msg: string, type: 'success' | 'error') => void;
    fullFileText?: string;
}

export const useAIPatternTeacher = ({
    gridData,
    setGridData,
    setActiveMapping,
    showToast
}: UseAIPatternTeacherProps) => {
    const [isInferringMapping, setIsInferringMapping] = useState(false);
    const [learnedPatternSource, setLearnedPatternSource] = useState<{ originalRaw: string[], corrected: any } | null>(null);

    const handleApplyCorrectionPattern = useCallback(async () => {
        if (!learnedPatternSource) return;

        setIsInferringMapping(true);
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });

        try {
            // Prompts mais rígidos e explicativos para evitar alucinações da IA
            const prompt = `Você é um Engenheiro de Dados especialista em extratos bancários.
            O Usuário Admin está te ENSINANDO um padrão fixo de extração através de um EXEMPLO REAL (Modelo de Ouro).

            DADOS DO EXEMPLO:
            - Linha Bruta (colunas separadas por ';'): "${learnedPatternSource.originalRaw.join(' ; ')}"
            - Como deve ficar o Nome/Descrição final: "${learnedPatternSource.corrected.description}"
            - Como deve ficar o Valor final: "${learnedPatternSource.corrected.amount}"
            - Como deve ficar a Data final: "${learnedPatternSource.corrected.date}"

            SUA TAREFA:
            1. Identifique os índices exatos (base zero) das colunas de Data, Descrição e Valor na linha bruta.
            2. Analise a coluna de descrição bruta e identifique quais partes o admin removeu para chegar no "Nome Corrigido". 
               Essas partes são "Palavras de Ruído" (ex: "PIX RECEBIDO", "TRANSF", "DOCTO").
            3. Crie uma regra de extração DETERMINÍSTICA baseada APENAS nestas posições. 

            REGRAS CRÍTICAS:
            - NUNCA tente adivinhar dados que não existem.
            - NUNCA sugira palavras de ruído que não apareçam claramente na linha bruta.
            - Seja extremamente conservador: o objetivo é fidelidade absoluta ao que o Admin ensinou.`;

            const response = await ai.models.generateContent({
                model: 'gemini-3-pro-preview',
                contents: prompt,
                config: { 
                    temperature: 0,
                    thinkingConfig: { thinkingBudget: 4000 },
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: {
                            dateColumnIndex: { type: Type.INTEGER, description: "Índice da coluna de data" },
                            descriptionColumnIndex: { type: Type.INTEGER, description: "Índice da coluna de descrição/nome" },
                            amountColumnIndex: { type: Type.INTEGER, description: "Índice da coluna de valor monetário" },
                            ignoredKeywords: { 
                                type: Type.ARRAY, 
                                items: { type: Type.STRING },
                                description: "Lista de termos fixos identificados como ruído na descrição" 
                            }
                        },
                        required: ["dateColumnIndex", "descriptionColumnIndex", "amountColumnIndex", "ignoredKeywords"]
                    }
                }
            });

            const result = JSON.parse(response.text || "{}");

            if (result && typeof result.dateColumnIndex === 'number') {
                setActiveMapping((prev: any) => ({
                    ...prev,
                    extractionMode: 'COLUMNS', // Força modo determinístico após aprendizado
                    dateColumnIndex: result.dateColumnIndex,
                    descriptionColumnIndex: result.descriptionColumnIndex,
                    amountColumnIndex: result.amountColumnIndex,
                    // Une as palavras aprendidas agora com as que o modelo já tinha, sem duplicar
                    ignoredKeywords: Array.from(new Set([
                        ...(prev.ignoredKeywords || []), 
                        ...(result.ignoredKeywords || [])
                    ].map(k => k.trim().toUpperCase()))).filter(k => k.length > 2)
                }));
                showToast("Padrão aprendido com sucesso! Aplicando regra rígida.", "success");
            }
        } catch (e: any) {
            console.error("[Teacher] Fail:", e);
            showToast("IA não conseguiu processar o padrão deste exemplo.", "error");
        } finally {
            setIsInferringMapping(false);
            setLearnedPatternSource(null);
        }
    }, [learnedPatternSource, setActiveMapping, showToast]);

    return {
        isInferringMapping,
        learnedPatternSource,
        setLearnedPatternSource,
        handleApplyCorrectionPattern
    };
};

import { GoogleGenAI, Type } from "@google/genai";
import { Transaction } from '../types';
import { Logger } from "./monitoringService";

const getAIClient = () => {
    if (!process.env.API_KEY) throw new Error("Chave de API do Gemini não configurada.");
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

const safeJsonParse = (input: any, fallback: any = []) => {
    if (!input) return fallback;
    let sanitized = String(input).trim();
    sanitized = sanitized.replace(/^```json\s*/g, '').replace(/\s*```$/g, '');

    try {
        const parsed = JSON.parse(sanitized);
        return parsed.rows || parsed.transactions || (Array.isArray(parsed) ? parsed : fallback);
    } catch (e) {
        return fallback;
    }
};

/**
 * INFERÊNCIA DE MAPEAMENTO (V42 - RIGOR ESTRUTURAL)
 */
export const inferMappingFromSample = async (sampleText: string): Promise<any> => {
    const ai = getAIClient();
    const prompt = `Analise este extrato bancário e identifique a estrutura de colunas e padrões de limpeza.
    Amostra do Extrato:
    ${sampleText}`;

    const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: prompt,
        config: { 
            temperature: 0, 
            thinkingConfig: { thinkingBudget: 2000 },
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    extractionMode: { type: Type.STRING, description: "'COLUMNS' para arquivos tabulares (Excel/CSV) ou 'BLOCK' para texto corrido/PDFs complexos" },
                    dateColumnIndex: { type: Type.INTEGER },
                    descriptionColumnIndex: { type: Type.INTEGER },
                    amountColumnIndex: { type: Type.INTEGER },
                    suggestedIgnoredKeywords: { 
                        type: Type.ARRAY, 
                        items: { type: Type.STRING },
                        description: "Termos repetitivos que não fazem parte do nome do pagador/recebedor"
                    },
                    skipRowsStart: { type: Type.INTEGER, description: "Número de linhas de cabeçalho a pular" }
                },
                required: ["extractionMode", "dateColumnIndex", "descriptionColumnIndex", "amountColumnIndex", "skipRowsStart"]
            }
        }
    });

    try {
        return JSON.parse(response.text || "{}");
    } catch (e) {
        return null;
    }
};

export const extractTransactionsWithModel = async (rawText: string, modelContext?: string): Promise<any> => {
    const ai = getAIClient();
    const finalPrompt = `Transforme o TEXTO em JSON seguindo o CONTRATO fornecido.
        ${modelContext ? `CONTRATO:\n${modelContext}\n` : ''}
        TEXTO:
        ${rawText}`;

    const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: finalPrompt,
        config: {
            temperature: 0,
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    rows: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                date: { type: Type.STRING },
                                description: { type: Type.STRING },
                                amount: { type: Type.NUMBER },
                                type: { type: Type.STRING },
                                paymentMethod: { type: Type.STRING }
                            },
                            required: ["date", "description", "amount"]
                        }
                    }
                },
                required: ["rows"]
            }
        }
    });
    return safeJsonParse(response.text);
};

export const extractTransactionsFromComplexBlock = async (rawText: string, globalContext?: string): Promise<any> => {
    return await extractTransactionsWithModel(rawText, globalContext);
};

export const extractStructuredDataByExample = async (rawText: string, globalContext?: string): Promise<any> => {
    return await extractTransactionsWithModel(rawText, globalContext);
};

import { useState, useCallback } from 'react';
import { GoogleGenAI, Type } from "@google/genai";
import { FileModel, Transaction } from '../types';

interface UseAIPatternTeacherProps {
    gridData: string[][];
    setGridData: (data: string[][]) => void;
    setActiveMapping: (mapping: any) => void;
    showToast: (msg: string, type: 'success' | 'error') => void;
    fullFileText?: string;
}

export const useAIPatternTeacher = ({
    gridData,
    setGridData,
    setActiveMapping,
    showToast
}: UseAIPatternTeacherProps) => {
    const [isInferringMapping, setIsInferringMapping] = useState(false);
    const [learnedPatternSource, setLearnedPatternSource] = useState<{ originalRaw: string[], corrected: any } | null>(null);

    const handleApplyCorrectionPattern = useCallback(async () => {
        if (!learnedPatternSource) return;

        setIsInferringMapping(true);
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });

        try {
            /**
             * PROMPT DE APRENDIZADO RÍGIDO (V2 - ANTI-ADIVINHAÇÃO)
             * Força a IA a agir como um comparador de strings determinístico.
             */
            const prompt = `VOCÊ É UM EXECUTOR DE REGRAS DETERMINÍSTICAS. NÃO ADIVINHE NADA.
            O Usuário Admin está te ensinando um padrão fixo através de um exemplo real que ele acabou de corrigir manualmente.

            DADOS PARA ANÁLISE:
            1. Linha Bruta Original: "${learnedPatternSource.originalRaw.join(' ; ')}"
            2. Correção do Admin (Modelo de Ouro):
               - Nome/Descrição Final: "${learnedPatternSource.corrected.description}"
               - Valor Final: "${learnedPatternSource.corrected.amount}"
               - Data Final: "${learnedPatternSource.corrected.date}"

            SUA MISSÃO ÚNICA:
            1. Identifique os índices (base zero) das colunas na Linha Bruta que contêm os dados acima.
            2. Compare o "Nome Final" do Admin com o texto original da coluna correspondente.
            3. Liste exatamente as palavras ou trechos de texto que o Admin REMOVEU do original para chegar no final. 
               Estes trechos são "Palavras de Ruído" (Ex: PIX, RECEBIDO, TRANSF).

            REGRA DE OURO:
            - Se você não encontrar o dado exato, retorne -1 para o índice.
            - NUNCA sugira palavras que não existam explicitamente na linha bruta.
            - O aprendizado deve ser RÍGIDO. Se o admin removeu "BANCO", a regra é remover "BANCO".`;

            const response = await ai.models.generateContent({
                model: 'gemini-3-pro-preview',
                contents: prompt,
                config: { 
                    temperature: 0,
                    thinkingConfig: { thinkingBudget: 2000 },
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: {
                            dateColumnIndex: { type: Type.INTEGER },
                            descriptionColumnIndex: { type: Type.INTEGER },
                            amountColumnIndex: { type: Type.INTEGER },
                            ignoredKeywords: { 
                                type: Type.ARRAY, 
                                items: { type: Type.STRING },
                                description: "Lista de termos fixos de ruído identificados através da comparação direta" 
                            }
                        },
                        required: ["dateColumnIndex", "descriptionColumnIndex", "amountColumnIndex", "ignoredKeywords"]
                    }
                }
            });

            const result = JSON.parse(response.text || "{}");

            if (result && typeof result.dateColumnIndex === 'number') {
                setActiveMapping((prev: any) => {
                    // Une as palavras aprendidas com as anteriores sem duplicatas
                    const newIgnored = Array.from(new Set([
                        ...(prev.ignoredKeywords || []), 
                        ...(result.ignoredKeywords || [])
                    ].map(k => k.trim().toUpperCase()))).filter(k => k.length > 2);

                    return {
                        ...prev,
                        extractionMode: 'COLUMNS', // Força modo determinístico após ensino manual
                        dateColumnIndex: result.dateColumnIndex,
                        descriptionColumnIndex: result.descriptionColumnIndex,
                        amountColumnIndex: result.amountColumnIndex,
                        ignoredKeywords: newIgnored
                    };
                });
                showToast("Padrão aprendido! O sistema agora seguirá este modelo rigidamente.", "success");
            }
        } catch (e: any) {
            console.error("[PatternTeacher] Critical Fail:", e);
            showToast("A IA não conseguiu processar este padrão específico.", "error");
        } finally {
            setIsInferringMapping(false);
            setLearnedPatternSource(null);
        }
    }, [learnedPatternSource, setActiveMapping, showToast]);

    return {
        isInferringMapping,
        learnedPatternSource,
        setLearnedPatternSource,
        handleApplyCorrectionPattern
    };
};
